        let collision = match rbtdri_invoke_global(ctx, RBTDGC_ENSCONCE_BOLE, &[deb_dir], pin) {
            Ok(r) => r,
            Err(e) => return rbtdre_Verdict::Fail(format!("collision ensconce invocation: {}", e)),
        };

